SELECT SUM(total) AS total_amount
FROM invoices
WHERE status = 'paid';

SELECT SUM(tax_amount) AS total_tax_amount
FROM transactions
WHERE transaction_type = 'check' AND target_field = 'transaction_date';

SELECT COUNT(*) AS total_issued_invoices
FROM invoices
WHERE status = 'issued' AND created_by = (SELECT user_id FROM users WHERE user_name = 'Alice Johnson');

SELECT COUNT(*) AS total_transactions 
FROM transactions 
WHERE created_by IN (
  SELECT DISTINCT user_id 
  FROM access_logs
);

SELECT strftime('%Y/%m/%d %H:%M:%S', transaction_date) AS formatted_date
FROM transactions
WHERE target_field = 'transaction_date';

SELECT COUNT(*) AS total_transactions
FROM transactions
WHERE invoice_id = 1;
